public class Box<T> {
    private T value;
    public void set(T v) { value = v; }
    public T get() { return value; }
    public static void main(String[] args) {
        Box<String> b1 = new Box<>();
        b1.set("SOLID");
        Box<Integer> b2 = new Box<>();
        b2.set(2025);
        System.out.println(b1.get() + " " + (b2.get() + 1));
    }
}
